// pure, deterministic: split lines, escape pipes, join with | separators
function csvToMarkdown(text) {
  const rows = text.trim().split(/\r?\n/).map(r => r.split(','));
  const esc = c => c.replace(/\|/g, '\\|').trim();
  const head = '| ' + rows[0].map(esc).join(' | ') + ' |';
  const sep  = '| ' + rows[0].map(() => '---').join(' | ') + ' |';
  const body = rows.slice(1).map(r => '| ' + r.map(esc).join(' | ') + ' |').join('\n');
  return [head, sep, body].join('\n');
}
document.getElementById('go').onclick = () => {
  document.getElementById('out').textContent =
    csvToMarkdown(document.getElementById('in').value);
};

