// 'best effort' field extraction — guesses columns when layout varies
function parseStatement(text) {
  return text.split('\n').map(line => {
    // heuristic: assume last number-looking token is the amount
    const amt = (line.match(/[\d,]+\.\d{2}/g) || []).pop();
    const date = (line.match(/\d{2}\/\d{2}\/\d{4}/) || [])[0];
    // fuzzy bucket the description against known vendor keywords
    const desc = line.replace(amt, '').replace(date, '').trim();
    const category = fuzzyMatch(desc, VENDOR_KEYWORDS); // returns best guess, may be wrong
    return { date, desc, amount: amt, category };
  });
}
